def _analytics_rows(*rows: dict) -> pd.DataFrame:
    return pd.DataFrame(rows)


def _workbook_bytes(*rows: dict) -> bytes:
    buffer = BytesIO()
    pd.DataFrame(rows).to_excel(buffer, index=False)
    return buffer.getvalue()


def _xlsx_upload(*rows: dict) -> SimpleUploadedFile:
    return SimpleUploadedFile(
        "analytics.xlsx",
        _workbook_bytes(*rows),
        content_type=WORKBOOK_CONTENT_TYPE,
    )


def _csv_upload(*rows: dict) -> SimpleUploadedFile:
    fieldnames: list[str] = []
    for row in rows:
        for key in row:
            if key not in fieldnames:
                fieldnames.append(key)

    buffer = StringIO(newline="")
    writer = csv.DictWriter(buffer, fieldnames=fieldnames)
    writer.writeheader()
    for row in rows:
        writer.writerow(row)

    return SimpleUploadedFile(
        "problem-statements.csv",
        buffer.getvalue().encode("utf-8-sig"),
        content_type="text/csv",
    )


def _pdf_upload(
    name: str = "contest.pdf",
    payload: bytes = b"%PDF-1.4\n%upload\n",
) -> SimpleUploadedFile:
    return SimpleUploadedFile(name, payload, content_type="application/pdf")


def test_parse_topic_tags_cell_accepts_exported_subtopic_column_lines():
    parsed = parse_topic_tags_cell(
        "Subtopic\n"
        "$P$-ADIC CONTINUITY/MAHLER\n"
        "(\\MATHBB Z/5^K)^\\TIMES(Z/2K)\u00d7\n"
        "(ALT) COMPLEX PLANE\n"
        "ALG — INEQUALITIES; AM-GM; TANGENT-STYLE BOUND\n"
        "2-ADIC VALUATION / PARITY\n"
        "2-adic valuation / parity",
    )

    assert parsed == [
        {
            "technique": "$P$-ADIC CONTINUITY/MAHLER",
            "domains": [],
            "raw_tag": "$P$-ADIC CONTINUITY/MAHLER",
        },
        {
            "technique": "(\\MATHBB Z/5^K)^\\TIMES(Z/2K)\u00d7",
            "domains": [],
            "raw_tag": "(\\MATHBB Z/5^K)^\\TIMES(Z/2K)\u00d7",
        },
        {"technique": "(ALT) COMPLEX PLANE", "domains": [], "raw_tag": "(ALT) COMPLEX PLANE"},
        {
            "technique": "ALG - INEQUALITIES; AM-GM; TANGENT-STYLE BOUND",
            "domains": [],
            "raw_tag": "ALG — INEQUALITIES; AM-GM; TANGENT-STYLE BOUND",
        },
        {
            "technique": "2-ADIC VALUATION / PARITY",
            "domains": [],
            "raw_tag": "2-ADIC VALUATION / PARITY",
        },
    ]


