def test_dataframe_from_excel_strips_headers_and_requires_columns():
    workbook_bytes = _workbook_bytes(
        {
            " YEAR ": 2026,
            " TOPIC ": "NT",
            " MOHS ": 4,
            " CONTEST ": "ISRAEL TST",
            " PROBLEM ": "P2",
            " CONTEST PROBLEM ": "ISRAEL TST 2026 P2",
            " Topic tags ": "Topic tags: NT - LTE",
        },
    )

    dataframe = dataframe_from_excel(workbook_bytes)

    assert list(dataframe.columns) == [
        "YEAR",
        "TOPIC",
        "MOHS",
        "CONTEST",
        "PROBLEM",
        "CONTEST PROBLEM",
        "Topic tags",
    ]

    missing_column_bytes = _workbook_bytes(
        {
            "YEAR": 2026,
            "TOPIC": "NT",
            "MOHS": 4,
            "CONTEST": "ISRAEL TST",
            "PROBLEM": "P2",
            "CONTEST PROBLEM": "ISRAEL TST 2026 P2",
        },
    )

    with pytest.raises(ProblemImportValidationError, match="Missing required column"):
        dataframe_from_excel(missing_column_bytes)


def test_import_problem_dataframe_creates_records_and_normalized_fields():
    dataframe = _analytics_rows(
        {
            "YEAR": 2026,
            "TOPIC": "NT",
            "MOHS": 4,
            "CONTEST": None,
            "PROBLEM": None,
            "CONTEST PROBLEM": "ISRAEL TST 2026 P2",
            "Topic tags": "Topic tags: NT - LTE, parity",
            "SOLVE DATE": "2026-01-15",
            "Confidence": "High",
            "IMO slot guess": "IMO slot guess: P1/4",
            "Core ideas": "Core ideas: Normalize into parity classes.",
            "Rationale": "Rationale: Short parity punchline.",
            "Pitfalls": "Common pitfalls: Greedy reasoning.",
        },
    )

    result = import_problem_dataframe(dataframe, replace_tags=False)

    assert result.n_records == EXPECTED_RECORD_COUNT
    assert result.n_techniques == EXPECTED_TWO_TECHNIQUES
    assert result.warnings == []

    record = ProblemSolveRecord.objects.get(year=2026)
    assert record.contest == "ISRAEL TST"
    assert record.problem == "P2"
    assert record.imo_slot_guess_value == "1,4"
    assert record.core_ideas_value == "Normalize into parity classes."
    assert record.rationale_value == "Short parity punchline."
    assert record.pitfalls_value == "Greedy reasoning."
    assert list(
        record.topic_techniques.order_by("technique").values_list("technique", flat=True),
    ) == ["LTE", "PARITY METHODS"]
    lte_tag = record.topic_techniques.get(technique="LTE")
    parity_tag = record.topic_techniques.get(technique="PARITY METHODS")
    assert lte_tag.lemma_theorem_tags == ["LTE"]
    assert lte_tag.object_tags == ["EXPONENT OF PRIME"]
    assert parity_tag.technique_tags == ["PARITY METHODS"]


def test_import_problem_dataframe_classifies_topic_tags_with_normalization_metadata():
    dataframe = _analytics_rows(
        {
            "YEAR": 2026,
            "TOPIC": "ALG",
            "MOHS": 25,
            "CONTEST": "Israel TST",
            "PROBLEM": "P1",
            "CONTEST PROBLEM": "Israel TST 2026 P1",
            "Topic tags": "Topic tags: ALG - cauchy equation; floor functions; 1]",
        },
    )

    result = import_problem_dataframe(dataframe, replace_tags=False)

    assert result.n_records == EXPECTED_RECORD_COUNT
    record = ProblemSolveRecord.objects.get(year=2026, contest="Israel TST", problem="P1")
    tags = {
        tag.technique: tag
        for tag in record.topic_techniques.order_by("technique")
    }
    assert tags["CAUCHY EQUATION"].raw_tag == "cauchy equation"
    assert tags["CAUCHY EQUATION"].main_topic == "ALG"
    assert tags["CAUCHY EQUATION"].canonical_subtopic == "Functional equations"
    assert tags["CAUCHY EQUATION"].normalization_status == "alias"
    assert tags["CAUCHY EQUATION"].normalization_confidence == "high"
