def test_contest_advanced_analytics_normal_user_sees_own_completions_only(client):
    """Completion heatmap and year solved counts use request.user, not global completions."""
    viewer = UserFactory()
    other = UserFactory()
    assert viewer.role == User.Role.NORMAL

    problem = ProblemSolveRecord.objects.create(
        year=2026,
        topic="ALG",
        mohs=6,
        contest="USAMO",
        problem="P1",
        contest_year_problem="USAMO 2026 P1",
        confidence="High",
    )
    ContestProblemStatement.objects.create(
        linked_problem=problem,
        contest_year=2026,
        contest_name="USAMO",
        problem_number=1,
        problem_code="P1",
        day_label="Day 1",
        statement_latex="Statement one",
    )
    UserProblemCompletion.objects.create(
        user=other,
        problem=problem,
        completion_date=date(2026, 1, 1),
    )

    client.force_login(viewer)
    response = client.get(reverse("pages:contest_advanced_dashboard"), {"contest": "USAMO"})
    assert response.status_code == HTTPStatus.OK
    year_row = next(row for row in response.context["year_rows"] if row["year"] == 2026)
    assert year_row["solved_problem_total"] == 0
    assert year_row["solved_rate"] == 0.0
    heatmap = response.context["contest_completion_heatmap"]
    row_2026 = next(row for row in heatmap["rows"] if row["year"] == 2026)
    cell_p1 = next(cell for cell in row_2026["cells"] if cell["problem_code"] == "P1")
    assert cell_p1["state"] == "unsolved"
    assert cell_p1["solution_url"] == reverse("solutions:problem_solution_list", args=[problem.problem_uuid])

    UserProblemCompletion.objects.create(
        user=viewer,
        problem=problem,
        completion_date=date(2026, 2, 2),
    )
    response_done = client.get(reverse("pages:contest_advanced_dashboard"), {"contest": "USAMO"})
    year_done = next(row for row in response_done.context["year_rows"] if row["year"] == 2026)
    assert year_done["solved_problem_total"] == 1
    assert year_done["solved_rate"] == 100.0
    heatmap_done = response_done.context["contest_completion_heatmap"]
    row_done = next(row for row in heatmap_done["rows"] if row["year"] == 2026)
    cell_done = next(cell for cell in row_done["cells"] if cell["problem_code"] == "P1")
    assert cell_done["state"] == "solved"
    assert cell_done["display"] == "✓"


def test_contest_mohs_summary_ranks_by_current_user_average(client):
    user = UserFactory()
    other = UserFactory()
    client.force_login(user)
    ContestMetadata.objects.create(
        contest="Hard Cup",
        tags=["Olympiad", "International"],
    )

    hard_statement = ContestProblemStatement.objects.create(
        contest_year=2026,
        contest_name="Hard Cup",
        problem_number=1,
        problem_code="P1",
        day_label="Day 1",
        statement_latex="Hard statement",
        topic="ALG",
        mohs=40,
    )
    easier_statement = ContestProblemStatement.objects.create(
        contest_year=2026,
        contest_name="Easier Cup",
        problem_number=1,
        problem_code="P1",
        day_label="Day 1",
        statement_latex="Easier statement",
        topic="GEO",
        mohs=20,
    )
    unsolved_statement = ContestProblemStatement.objects.create(
        contest_year=2026,
        contest_name="Unsolved Cup",
        problem_number=1,
        problem_code="P1",
        day_label="Day 1",
        statement_latex="Unsolved statement",
        topic="NT",
        mohs=35,
    )
    UserProblemCompletion.objects.create(user=user, statement=easier_statement, completion_date=date(2026, 1, 2))
    UserProblemCompletion.objects.create(user=user, statement=hard_statement, completion_date=date(2026, 1, 1))
    UserProblemCompletion.objects.create(user=other, statement=unsolved_statement, completion_date=date(2026, 1, 3))

    response = client.get(reverse("pages:contest_mohs_summary"))

    assert response.status_code == HTTPStatus.OK
    rows = response.context["contest_mohs_summary_rows"]
    assert [row["contest"] for row in rows] == ["Hard Cup", "Easier Cup", "Unsolved Cup"]
    assert response.context["contest_mohs_topic_legend"] == [
        {"code": "A", "label": "Algebra"},
        {"code": "C", "label": "Combinatorics"},
        {"code": "G", "label": "Geometry"},
        {"code": "N", "label": "Number Theory"},
    ]
    assert response.context["contest_mohs_summary_stats"]["has_user_averages"] is True
    assert response.context["contest_mohs_summary_stats"]["overall_average_mohs"] == 31.67
    hard_row = rows[0]
    assert hard_row["level_labels"] == ["Olympiad", "International"]
    assert hard_row["levels"] == "Olympiad, International"
    assert hard_row["topic_averages"]["A"] == 40.0
    assert hard_row["topic_counts"]["A"] == 1
    assert hard_row["average_mohs"] == 40.0
    assert hard_row["total_count"] == 1
    assert hard_row["user_average_mohs"] == 40.0
    assert hard_row["user_completion_count"] == 1
    assert hard_row["contest_url"] == reverse("pages:contest_dashboard_listing") + "?contest=Hard+Cup"
    assert response.context["contest_mohs_summary_stats"]["has_user_averages"] is True
    assert (
        response.context["contest_mohs_summary_stats"]["rank_description"]
        == "Ranked by My Avg from completed problems"
    )

    unsolved_row = rows[2]
    assert unsolved_row["user_average_mohs"] is None
    assert unsolved_row["user_average_sort"] == -1
    assert unsolved_row["user_completion_count"] == 0


